#-----------------------Selección aleatoria de tipos de usuario---------------

def generar_tipo_usuario():
    tipos = list(usuarios.keys())

    probabilidades = [
        usuarios[t]['prob']
        for t in tipos
    ]

    return np.random.choice(
        tipos,
        p=probabilidades
    )
