#-------------------------Estructura de un cliente--------------------

class Cliente:
    def __init__(self, tipo, tiempo_llegada):
        self.tipo = tipo
        self.tiempo_llegada = tiempo_llegada
        self.inicio_servicio = None
        self.tiempo_salida = None
        self.tiempo_espera = None
        self.tiempo_sistema = None
        self.tiempo_servicio = None


#----------------------------------- Clase CajeroMM1 ---------------------------

class CajeroMM1:
    def __init__(self, id_cajero):
        self.id = id_cajero

        # Cola FIFO
        self.cola = deque()

        # Estado del servidor
        self.ocupado = False
        self.cliente_actual = None
        self.proxima_salida = float('inf')

        # Estadísticas
        self.clientes_atendidos = 0
        self.tiempo_ocupado = 0
        self.tiempos_espera = []
        self.tiempos_sistema = []
        self.tiempos_servicio = []

        # Punto 2
        self.usuarios_por_tipo = {
            'rapido': 0,
            'normal': 0,
            'lento': 0,
            'muy_lento': 0
        }

        self.tiempos_por_tipo = {
            'rapido': [],
            'normal': [],
            'lento': [],
            'muy_lento': []
        }

#---------------------------------- IC95 ----------------------------------
def intervalo_confianza(datos):
    media = np.mean(datos)
    std = np.std(datos, ddof=1)
    n = len(datos)

    t_critico = stats.t.ppf(0.975, n - 1)
    margen_error = t_critico * (std / np.sqrt(n))

    return (
        media,
        media - margen_error,
        media + margen_error
    )


#--------------------------------Inicio de Simulación---------------------------
class SimulacionParqueadero:
    def __init__(self, tiempo_simulacion):
        self.tiempo_simulacion = tiempo_simulacion
        self.tiempo_actual = 0
        self.eventos = []
        self.evolucion_sistema = []



        self.cajeros = [
            CajeroMM1(1),
            CajeroMM1(2),
            CajeroMM1(3)
        ]

        self.total_clientes = 0

        # Métricas globales del sistema
        self.longitudes_cola = []
        self.tiempos_espera_sistema = []
        self.tiempos_sistema_sistema = []
        self.tiempos_servicio_sistema = []
        self.evolucion_espera = []

        self.usuarios_por_tipo_sistema = {
            'rapido': 0,
            'normal': 0,
            'lento': 0,
            'muy_lento': 0
        }

        self.tiempos_por_tipo_sistema = {
            'rapido': [],
            'normal': [],
            'lento': [],
            'muy_lento': []
        }

        self.servicios_por_tipo_sistema = {
          'rapido': [],
          'normal': [],
          'lento': [],
          'muy_lento': []
      }

    # ---------------------------------
    # Programar eventos
    # ---------------------------------
    def programar_evento(self, tiempo, tipo_evento, datos=None):
        self.eventos.append(
            (tiempo, tipo_evento, datos)
        )
        self.eventos.sort(key=lambda x: x[0])

    # ---------------------------------
    # Seleccionar fila más corta
    # ---------------------------------
    def seleccionar_cajero(self):
        longitudes = []

        for cajero in self.cajeros:
            longitud = len(cajero.cola)
            if cajero.ocupado:
                longitud += 1
            longitudes.append(longitud)

        minimo = min(longitudes)
        candidatos = []

        for i, longitud in enumerate(longitudes):
            if longitud == minimo:
                candidatos.append(i)

        indice = np.random.choice(candidatos)
        return self.cajeros[indice]

    # ---------------------------------
    # Generar tiempo llegada
    # ---------------------------------
    def generar_tiempo_llegada(self, tipo_usuario):
        media_llegada = usuarios[tipo_usuario]['llegada']
        return np.random.exponential(media_llegada)

    # ---------------------------------
    # Generar tiempo servicio
    # ---------------------------------
    def generar_tiempo_servicio(self, tipo_usuario):
        media_servicio = usuarios[tipo_usuario]['servicio']
        return np.random.exponential(media_servicio)

    def iniciar_servicio(self, cajero, cliente):
        cliente.inicio_servicio = self.tiempo_actual
        tiempo_servicio = self.generar_tiempo_servicio(cliente.tipo)
        cliente.tiempo_servicio = tiempo_servicio

        cajero.ocupado = True
        cajero.cliente_actual = cliente
        cajero.tiempo_ocupado += tiempo_servicio

        self.programar_evento(
            self.tiempo_actual + tiempo_servicio,
            "SALIDA",
            cajero
        )

    def procesar_llegada(self):
        tipo_usuario = generar_tipo_usuario()
        cliente = Cliente(tipo_usuario, self.tiempo_actual)
        self.total_clientes += 1

        cajero = self.seleccionar_cajero()

        if not cajero.ocupado:
            self.iniciar_servicio(cajero, cliente)
        else:
            cajero.cola.append(cliente)

        # Registrar longitud de cola
        self.longitudes_cola.append(len(cajero.cola))

        # Programar próxima llegada
        siguiente_tipo = generar_tipo_usuario()
        tiempo_entre_llegadas = self.generar_tiempo_llegada(siguiente_tipo)

        self.programar_evento(
            self.tiempo_actual + tiempo_entre_llegadas,
            "LLEGADA"
        )

    def procesar_salida(self, cajero):
        self.longitudes_cola.append(len(cajero.cola))
        cliente = cajero.cliente_actual
        cliente.tiempo_salida = self.tiempo_actual

        cliente.tiempo_espera = cliente.inicio_servicio - cliente.tiempo_llegada

        self.evolucion_espera.append(
                  cliente.tiempo_espera
              )
        cliente.tiempo_sistema = cliente.tiempo_salida - cliente.tiempo_llegada
        self.evolucion_sistema.append(
          cliente.tiempo_sistema
      )

        # ==================================
        # Estadísticas del cajero
        # ==================================
        cajero.clientes_atendidos += 1
        cajero.tiempos_espera.append(cliente.tiempo_espera)
        cajero.tiempos_sistema.append(cliente.tiempo_sistema)
        cajero.tiempos_servicio.append(cliente.tiempo_servicio)

        cajero.usuarios_por_tipo[cliente.tipo] += 1
        cajero.tiempos_por_tipo[cliente.tipo].append(cliente.tiempo_sistema)

        # ==================================
        # Estadísticas globales del sistema
        # ==================================
        self.tiempos_espera_sistema.append(cliente.tiempo_espera)
        self.tiempos_sistema_sistema.append(cliente.tiempo_sistema)
        self.tiempos_servicio_sistema.append(cliente.tiempo_servicio)

        self.servicios_por_tipo_sistema[
              cliente.tipo
          ].append(
              cliente.tiempo_servicio
          )

        self.usuarios_por_tipo_sistema[cliente.tipo] += 1
        self.tiempos_por_tipo_sistema[cliente.tipo].append(cliente.tiempo_sistema)

        # ==================================
        # Revisar cola
        # ==================================
        if len(cajero.cola) > 0:
            siguiente_cliente = cajero.cola.popleft()
            self.iniciar_servicio(cajero, siguiente_cliente)
        else:
            cajero.ocupado = False
            cajero.cliente_actual = None

    def ejecutar(self):
        tipo_inicial = generar_tipo_usuario()
        self.programar_evento(
            self.generar_tiempo_llegada(tipo_inicial),
            "LLEGADA"
        )

        while len(self.eventos) > 0:
            tiempo, tipo_evento, datos = self.eventos.pop(0)
            self.tiempo_actual = tiempo

            if self.tiempo_actual > self.tiempo_simulacion:
                break

            if tipo_evento == "LLEGADA":
                self.procesar_llegada()
            elif tipo_evento == "SALIDA":
                self.procesar_salida(datos)

        return self.cajeros


#------------------------FUNCION PARA IMPRIMIR -------------------
def imprimir_estadisticas(nombre, datos):
    media = np.mean(datos)
    std = np.std(datos, ddof=1)
    inferior, superior = intervalo_confianza(datos)[1:]

    print(f"\n{nombre}")
    print(f"Media: {media:.4f}")
    print(f"Std: {std:.4f}")
    print(f"Min: {np.min(datos):.4f}")
    print(f"Max: {np.max(datos):.4f}")
    print(f"IC95: [{inferior:.4f}, {superior:.4f}]")


#---------------------------------SIMULACION-----------------------------------

NUM_REPLICAS = 30

def ejecutar_replicas():
    replicas = []

    for replica in range(NUM_REPLICAS):
        sim = SimulacionParqueadero(TIEMPO_SIMULACION)
        sim.ejecutar()
        replicas.append(sim)

    return replicas


def analizar_replicas(replicas):
    usuarios_totales = {
        'rapido': 0,
        'normal': 0,
        'lento': 0,
        'muy_lento': 0
    }

    servicios_tipo = {
    'rapido': [],
    'normal': [],
    'lento': [],
    'muy_lento': []
}

    tiempos_tipo = {
        'rapido': [],
        'normal': [],
        'lento': [],
        'muy_lento': []
    }

    esperas = []
    sistemas = []
    colas = []
    servicios = []
    utilizaciones = []

    clientes_c1 = []
    clientes_c2 = []
    clientes_c3 = []

    util_c1 = []
    util_c2 = []
    util_c3 = []

    servicio_c1 = []
    servicio_c2 = []
    servicio_c3 = []

    for sim in replicas:



        for tipo in servicios_tipo:

          servicios_tipo[tipo].extend(
              sim.servicios_por_tipo_sistema[tipo]
          )
        for tipo in tiempos_tipo:
            tiempos_tipo[tipo].extend(sim.tiempos_por_tipo_sistema[tipo])
            usuarios_totales[tipo] += sim.usuarios_por_tipo_sistema[tipo]

        c1 = sim.cajeros[0]
        c2 = sim.cajeros[1]
        c3 = sim.cajeros[2]

        clientes_c1.append(c1.clientes_atendidos)
        clientes_c2.append(c2.clientes_atendidos)
        clientes_c3.append(c3.clientes_atendidos)

        util_c1.append(c1.tiempo_ocupado / TIEMPO_SIMULACION)
        util_c2.append(c2.tiempo_ocupado / TIEMPO_SIMULACION)
        util_c3.append(c3.tiempo_ocupado / TIEMPO_SIMULACION)

        servicios.append(np.mean(sim.tiempos_servicio_sistema))

        tiempo_ocupado_total = sum(cajero.tiempo_ocupado for cajero in sim.cajeros)
        utilizaciones.append(tiempo_ocupado_total / (3 * TIEMPO_SIMULACION))

        esperas.append(np.mean(sim.tiempos_espera_sistema))
        sistemas.append(np.mean(sim.tiempos_sistema_sistema))
        colas.append(np.mean(sim.longitudes_cola))

        servicio_c1.append(np.mean(sim.cajeros[0].tiempos_servicio))
        servicio_c2.append(np.mean(sim.cajeros[1].tiempos_servicio))
        servicio_c3.append(np.mean(sim.cajeros[2].tiempos_servicio))

    imprimir_estadisticas("TIEMPO ESPERA", esperas)
    imprimir_estadisticas("TIEMPO SISTEMA", sistemas)
    imprimir_estadisticas("TIEMPO SERVICIO", servicios)
    imprimir_estadisticas("LONGITUD COLA", colas)
    imprimir_estadisticas("UTILIZACION", utilizaciones)

    imprimir_estadisticas("CLIENTES CAJERO 1", clientes_c1)
    imprimir_estadisticas("CLIENTES CAJERO 2", clientes_c2)
    imprimir_estadisticas("CLIENTES CAJERO 3", clientes_c3)

    imprimir_estadisticas("UTILIZACION CAJERO 1", util_c1)
    imprimir_estadisticas("UTILIZACION CAJERO 2", util_c2)
    imprimir_estadisticas("UTILIZACION CAJERO 3", util_c3)

    print("\nUSUARIOS POR TIPO")
    total = sum(usuarios_totales.values())

    for tipo, cantidad in usuarios_totales.items():
        porcentaje = (cantidad / total) * 100
        print(f"{tipo}: {cantidad} ({porcentaje:.2f}%)")

    print("\nTIEMPOS PROMEDIO POR TIPO")
    for tipo, tiempos in tiempos_tipo.items():
        print(f"{tipo}: {np.mean(tiempos):.4f} min")

    promedio_clientes = np.mean([
        np.mean(clientes_c1),
        np.mean(clientes_c2),
        np.mean(clientes_c3)
    ])

    promedio_utilizacion = np.mean([
        np.mean(util_c1),
        np.mean(util_c2),
        np.mean(util_c3)
    ])

    print("\nPROMEDIOS AGREGADOS")
    print(f"Clientes atendidos: {promedio_clientes:.2f}")
    print(f"Utilización: {promedio_utilizacion:.4f}")

    imprimir_estadisticas("TIEMPO ATENCION CAJERO 1", servicio_c1)
    imprimir_estadisticas("TIEMPO ATENCION CAJERO 2", servicio_c2)
    imprimir_estadisticas("TIEMPO ATENCION CAJERO 3", servicio_c3)

    return {
        "esperas": esperas,
        "sistemas": sistemas,
        "servicios": servicios,
        "colas": colas,
        "utilizaciones": utilizaciones,
        "clientes_c1": clientes_c1,
        "clientes_c2": clientes_c2,
        "clientes_c3": clientes_c3,
        "util_c1": util_c1,
        "util_c2": util_c2,
        "util_c3": util_c3,
        "servicio_c1": servicio_c1,
        "servicio_c2": servicio_c2,
        "servicio_c3": servicio_c3,
        "usuarios_totales": usuarios_totales,
        "tiempos_tipo": tiempos_tipo,
        "servicios_tipo": servicios_tipo
    }
replicas = ejecutar_replicas()
resultados = analizar_replicas(replicas)

medias_acumuladas = []

for i in range(len(resultados["sistemas"])):
    medias_acumuladas.append(
        np.mean(
            resultados["sistemas"][:i+1]
        )
    )
plt.figure(figsize=(10,5))

plt.plot(
    medias_acumuladas,
    marker="o"
)

plt.xlabel("Número de réplicas")
plt.ylabel("Media acumulada")
plt.title(
    "Convergencia del tiempo promedio en el sistema"
)

plt.grid(True)
plt.show()

"""#PUNTO1

Para determinar si el número de réplicas era suficiente, se analizó la convergencia de la media acumulada del tiempo promedio en el sistema. Los resultados muestran que durante las primeras réplicas existe una variabilidad considerable; sin embargo, a partir de aproximadamente la réplica 20 la media acumulada comienza a estabilizarse y presenta únicamente fluctuaciones pequeñas alrededor de un valor cercano a 3.88 minutos.

Debido a que entre las réplicas 20 y 30 no se observan cambios significativos en la estimación de la media, se concluye que el sistema ha alcanzado estabilidad estadística. Por lo tanto, las 30 réplicas ejecutadas son suficientes para obtener estimaciones confiables de las métricas de desempeño del sistema.
"""

import pandas as pd
import numpy as np
from scipy import stats


print(" ---------TIEMPOS DE ATENCION POR CAJERO------------")

cajeros = {
    1: resultados["servicio_c1"],
    2: resultados["servicio_c2"],
    3: resultados["servicio_c3"]
}

estadisticas = []
intervalos = []

for cajero, datos in cajeros.items():

    media = np.mean(datos)
    std = np.std(datos, ddof=1)
    minimo = np.min(datos)
    maximo = np.max(datos)

    n = len(datos)

    t_critico = stats.t.ppf(0.975, n-1)
    margen = t_critico * (std / np.sqrt(n))

    ic_inf = media - margen
    ic_sup = media + margen

    estadisticas.append([
        cajero,
        media,
        std,
        minimo,
        maximo
    ])

    intervalos.append([
        cajero,
        media,
        ic_inf,
        ic_sup
    ])

tabla_cajeros = pd.DataFrame(
    estadisticas,
    columns=[
        "Cajero",
        "Media",
        "Desv_Estandar",
        "Minimo",
        "Maximo"
    ]
)

tabla_ic = pd.DataFrame(
    intervalos,
    columns=[
        "Cajero",
        "Media",
        "IC95_Inf",
        "IC95_Sup"
    ]
)

display(tabla_cajeros.round(4))
display(tabla_ic.round(4))

cajero_eficiente = tabla_cajeros.loc[
    tabla_cajeros["Media"].idxmin()
]

cajero_ineficiente = tabla_cajeros.loc[
    tabla_cajeros["Media"].idxmax()
]

print("\n" + "="*50)
print("CAJERO MÁS EFICIENTE")
