# ==========================================

def obtener_resumen(replicas, num_cajeros):

    esperas = []
    sistemas = []
    colas = []
    utilizaciones = []

    for sim in replicas:

        esperas.append(
            np.mean(sim.tiempos_espera_sistema)
        )

        sistemas.append(
            np.mean(sim.tiempos_sistema_sistema)
        )

        colas.append(
            np.mean(sim.longitudes_cola)
        )

        tiempo_ocupado_total = sum(
            cajero.tiempo_ocupado
            for cajero in sim.cajeros
        )

        utilizaciones.append(
            tiempo_ocupado_total /
            (num_cajeros * TIEMPO_SIMULACION)
        )

    return {
        "Cajeros": num_cajeros,
        "Espera": np.mean(esperas),
        "Sistema": np.mean(sistemas),
        "Utilizacion": np.mean(utilizaciones),
        "Cola": np.mean(colas)
    }

